package com.baize.flux.server.http.servlet; import com.baize.flux.server.http.FluxServlet; import com.baize.flux.server.service.JobRestService; import javax.servlet.http.*; import java.io.*; public final class JobInfoServlet extends FluxServlet {public JobInfoServlet(JobRestService s){super(s);} protected void doGet(HttpServletRequest q,HttpServletResponse p)throws IOException{try{write(p,200,service.job(q.getPathInfo().substring(1)));}catch(Exception e){error(q,p,e);}} protected void doDelete(HttpServletRequest q,HttpServletResponse p)throws IOException{try{String id=q.getPathInfo().substring(1);service.cancel(id);java.util.Map<String,String>x=new java.util.LinkedHashMap<String,String>();x.put("jobId",id);x.put("status","CANCELLING");write(p,202,x);}catch(Exception e){error(q,p,e);}}}
